fn identity_lut(size: usize) -> LutGrid {
    let mut lut = LutGrid::new(size);
    for ri in 0..size {
        for gi in 0..size {
            for bi in 0..size {
                let r = ri as f32 / (size - 1) as f32;
                let g = gi as f32 / (size - 1) as f32;
                let b = bi as f32 / (size - 1) as f32;
                lut.set(ri, gi, bi, [r, g, b]);
            }
        }
    }
    lut
}
